int p003_below_zero(int *operations, int operations_size)
/*@ With l
    Require 0 <= operations_size && operations_size < INT_MAX &&
        (forall (k: Z), (0 <= k && k < operations_size) =>
            (INT_MIN <= sum(sublist(0, k + 1, l)) &&
