        (__return == 0) &&
        (forall (k: Z), (0 <= k && k < operations_size) =>
               0 <= sum(sublist(0, k + 1, l)))) &&
       IntArray::full(operations, operations_size, l)
*/
{
    int num = 0;
    int i;

    for (i = 0; i < operations_size; i++) {
        num += operations[i];
        if (num < 0) {
