int arr_sum_pointer(int n, int *a)
/*@ With l
    Require 0 < n && n < 100 && IntArray::full(a, n, l) && (forall (i: Z), (0 <= i && i < n) => (0 <= l[i] && l[i] < 100))
    Ensure  __return == sum(l) && IntArray::full(a, n, l)
*/
{
  int i = 0;
  int ret = 0;
  int *endp = a + n;
  /*@ Inv
      0 <= i && i <= n && n == n@pre && ret == sum(sublist(0, i, l)) */
  while (endp - (a + i) != 0) {
    /*@ i != n */
    ret += *(a + i);
    ++i;
  }
  return ret;
}

/*
brackets is a string of '<' && '>'.
return true if every opening bracket has a corresponding closing bracket.

>>> p056_correct_bracketing("<")
false
>>> p056_correct_bracketing("<>")
true
>>> p056_correct_bracketing("<<><>>")
true
>>> p056_correct_bracketing("><<>")
false
*/
#include "verification_stdlib.h"
#include "verification_list.h"
#include "char_array_def.h"

/*@ Extern Coq (problem_56_pre: list Z -> Prop)
               (problem_56_spec: list Z -> Z -> Prop)
               (angle_level_upto: Z -> list Z -> Z)
               (angle_nonnegative_prefix: Z -> list Z -> Prop)
               (ascii_range: list Z -> Prop) */
/*@ Import Coq Require Import p056_correct_bracketing */

int strlen(char *s)
/*@ With l n
    Require CharArray::full(s, n + 1, app(l, cons(0, nil)))
    Ensure __return == n &&
           CharArray::full(s, n + 1, app(l, cons(0, nil)))
*/
;

int p056_correct_bracketing(char *brackets)
/*@ With l len
    Require
        0 <= len && len < INT_MAX &&
        Zlength(l) == len &&
        ascii_range(l) &&
        problem_56_pre(l) &&
        CharArray::full(brackets, len + 1, app(l, cons(0, nil)))
    Ensure
        problem_56_spec(l, __return) &&
        CharArray::full(brackets, len + 1, app(l, cons(0, nil)))
*/
{
    int level = 0;
    int n = strlen(brackets);
    int i;

    for (i = 0; i < n; i++) {
        if (brackets[i] == 60) {
            level = level + 1;
        } else if (brackets[i] == 62) {
            level = level - 1;
        }
        if (level < 0) {
            return 0;
        }
    }
    if (level != 0) {
        return 0;
    }
    return 1;
}

/*
For a given vector of integers, return a vector consisting of a sum && a product of all the integers in a vector.
Empty sum should be equal to 0 && empty product should be equal to 1.
>>> p008_sum_product({})
(0, 1)
>>> p008_sum_product({1, 2, 3, 4})
(10, 24)
*/
#include "verification_stdlib.h"
#include "verification_list.h"
#include "int_array_def.h"

/*@ Extern Coq (problem_8_pre: Prop)
               (problem_8_spec: list Z -> Z -> Z -> Prop)
               (list_int_range: list Z -> Prop)
               (prefix_sum: list Z -> Z -> Z)
               (prefix_product: list Z -> Z -> Z)
               (prefix_sum_product_int_range: list Z -> Z -> Prop) */
/*@ Import Coq Require Import p008_sum_product */

int *malloc_int_array(int size)
/*@ Require size >= 0 && size < INT_MAX
    Ensure __return != 0 && IntArray::undef_full(__return, size)
*/;

int *p008_sum_product(int *numbers, int numbers_size)
/*@ With lv (numbers0: Z) (numbers_size0: Z)
    Require
        numbers == numbers0 &&
        numbers_size == numbers_size0 &&
        0 <= numbers_size0 && numbers_size0 < INT_MAX &&
        problem_8_pre &&
        list_int_range(lv) &&
        prefix_sum_product_int_range(lv, numbers_size0) &&
        IntArray::full(numbers, numbers_size, lv)
    Ensure
        exists s p,
        __return != 0 &&
        problem_8_spec(lv, s, p) &&
        IntArray::full(numbers0, numbers_size0, lv) *
        IntArray::full(__return, 2, cons(s, cons(p, nil)))
*/
{
    int sum = 0;
    int product = 1;
    int i;
    int *out = malloc_int_array(2);

    for (i = 0; i < numbers_size; i++) {
        sum += numbers[i];
        product *= numbers[i];
    }

    out[0] = sum;
    out[1] = product;
    return out;
}

